diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 60da48e1d95d..0b65d6daa9a9 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -3888,6 +3888,21 @@ Instruction *InstCombinerImpl::foldICmpEqIntrinsicWithConstant(
       return new ICmpInst(NewPred, II->getArgOperand(0), II->getArgOperand(1));
     }
     break;
+  case Intrinsic::smin: {
+    // icmp eq X, smin(smax(X, Lo), Hi) -> icmp ult (X - Lo), (Hi - Lo + 1)
+    // This checks if X is within the range [Lo, Hi].
+    Value *Inner = II->getArgOperand(0);
+    const APInt *Lo, *Hi;
+    if (match(II->getArgOperand(1), m_APInt(Hi)) &&
+        match(Inner, m_SMax(m_Specific(Cmp.getOperand(0)), m_APInt(Lo)))) {
+      if (Lo->sle(*Hi)) {
+        // Range is [Lo, Hi]. Check if X is in range by computing (X - Lo) <u (Hi - Lo + 1)
+        APInt RangeSize = *Hi - *Lo + 1;
+        Value *Sub = Builder.CreateSub(Cmp.getOperand(0), ConstantInt::get(Ty, *Lo));
+        return new ICmpInst(ICmpInst::ICMP_ULT, Sub, ConstantInt::get(Ty, RangeSize));
+      }
+    }
+    break;
   }
   default:
     break;
@@ -3896,6 +3911,10 @@ Instruction *InstCombinerImpl::foldICmpEqIntrinsicWithConstant(
   return nullptr;
 }

